// Get data from prior nodes
const productsQueryResults = $('Products Query').all();

let facetsQueryResults = [];
try {
  facetsQueryResults = $('Facets Query').all();
} catch (e) {
  facetsQueryResults = []; // Facets Query not executed (that's OK)
}

// Extract products records
const productsData = productsQueryResults[0]?.json?.records || productsQueryResults[0]?.json || [];
const productRecords = Array.isArray(productsData) ? productsData : [productsData];

// total_count
const totalCount =
  productRecords[0]?.fields?.total_count ??
  productRecords[0]?.total_count ??
  productRecords.length;

function normalizeProduct(record) {
  const fields = record.fields || record;
  return {
    sku: fields.sku,
    name: fields.name,
    price: fields.price,
    unit_name: fields.unit_name,
    color: fields.color,
    height_ft: fields.height_ft,
    height_in: fields.height_in || fields.height_normal_in,
    mesh_type: fields.mesh_type,
    pipe_diameter_in: fields.pipe_diameter_in,
    pipe_diameter_label: fields.pipe_diameter_label,
    length_ft: fields.length_ft,
    wall_thickness: fields.wall_thickness,
    material_grade: fields.material_grade,
    end_type: fields.end_type,
    units_of_measure: fields.units_of_measure,
  };
}

const products = productRecords.map(normalizeProduct);

// mode
let mode;
if (totalCount === 0) mode = 'none';
else if (totalCount === 1) mode = 'exact';
else if (totalCount <= 5) mode = 'full';
else if (totalCount <= 20) mode = 'guided';
else mode = 'narrow';

// facets
let facets = null;
let suggested_filter = null;

if (totalCount > 5 && facetsQueryResults.length > 0) {
  const facetsData = facetsQueryResults[0]?.json?.records || facetsQueryResults[0]?.json || [];
  const facetRecords = Array.isArray(facetsData) ? facetsData : [facetsData];

  facets = {};

  for (const record of facetRecords) {
    const r = record.fields || record;
    const field = r.field;
    const value = r.value;
    const cnt = r.cnt;

    if (!field || value === null || value === undefined || value === '') continue;

    if (!facets[field]) facets[field] = { values: [], counts: [] };
    facets[field].values.push(value);
    facets[field].counts.push(cnt);
  }

  for (const field of Object.keys(facets)) {
    if (facets[field].values.length <= 1) delete facets[field];
  }

  let bestField = null;
  let bestScore = 0;

  for (const [field, data] of Object.entries(facets)) {
    const maxCount = Math.max(...data.counts);
    const score = 1 - (maxCount / totalCount);
    if (score > bestScore && data.values.length >= 2) {
      bestScore = score;
      bestField = field;
    }
  }

  suggested_filter = bestField;
}

// response
const response = {
  mode,
  total_count: totalCount,
  products: products.slice(0, 5),
};

if (facets && Object.keys(facets).length > 0) {
  response.facets = facets;
  response.suggested_filter = suggested_filter;
}

if (mode === 'none') response.message = "No products found matching your criteria.";

return [{ json: response }];

const items = $("When Executed from MCP Trigger Call").all();

  function notEmpty(value) {
    if (value === undefined || value === null) return false;
    if (typeof value === 'string' && value.trim() === '') return false;
    return true;
  }

  const TABLE_NAME = 'Products_summary_active_description_family_code_name_price_sku_unit_code';

  const PRODUCT_COLUMNS = [
    'sku', 'family_code', 'unit_name', 'name', 'price', 'color',
    'height_ft', 'height_in', 'height_normal_in', 'mesh_type',
    'pipe_diameter_in', 'pipe_diameter_label', 'length_ft',
    'wall_thickness', 'material_grade', 'end_type', 'units_of_measure'
  ].join(', ');

  const FACET_FIELDS = [
    'unit_name', 'color', 'height_ft', 'mesh_type',
    'pipe_diameter_label', 'length_ft', 'wall_thickness', 'material_grade'
  ];

  const out = items.map(item => {
    const q = item.json.query || item.json || {};

    const where = [];
    const args = [];

    // 🔒 HARD-CODED family_code
    where.push('family_code = ?');
    args.push(5);

    if (notEmpty(q.unit_name)) {
      where.push('unit_name = ?');
      args.push(q.unit_name);
    }

    if (notEmpty(q.color)) {
      let normalizedColor = q.color;

      if (q.unit_name === 'Mesh' && (q.color === 'Green' || q.color === 'Black')) {
        normalizedColor = 'Black/Green';
      }

      where.push('color = ?');
      args.push(normalizedColor);
    }

    if (notEmpty(q.height_in) && Number(q.height_in) !== 0 && q.unit_name === "Mesh") {
      where.push('height_normal_in = ?');
      args.push(Number(q.height_in));
    } else if (notEmpty(q.height_ft) && Number(q.height_ft) !== 0 && q.unit_name === "Mesh") {
      where.push('height_normal_in = ?');
      args.push(Number(q.height_ft) * 12);
    }

    if (notEmpty(q.mesh_type)) {
      where.push('mesh_type = ?');
      args.push(q.mesh_type);
    }

    if (notEmpty(q.pipe_diameter_label)) {
      where.push('pipe_diameter_label = ?');
      args.push(q.pipe_diameter_label);
    }

    if (notEmpty(q.length_ft) && Number(q.length_ft) !== 0) {
      where.push('length_ft = ?');
      args.push(Number(q.length_ft));
    }

    if (notEmpty(q.wall_thickness) && Number(q.wall_thickness) !== 0) {
      where.push('wall_thickness = ?');
      args.push(Number(q.wall_thickness));
    }

    if (notEmpty(q.material_grade)) {
      where.push('material_grade = ?');
      args.push(q.material_grade);
    }

    if (notEmpty(q.end_type)) {
      where.push('end_type = ?');
      args.push(q.end_type);
    }

    const active = typeof q.active === 'boolean' ? q.active : true;
    where.push('active = ?');
    args.push(active);

    const whereClause = ' WHERE ' + where.join(' AND ');

    // --- Facets query: DISTINCT values + counts for each field ---
    const facetQueries = FACET_FIELDS.map(field =>
      `SELECT '${field}' as field, ${field} as value, COUNT(*) as cnt ` +
      `FROM ${TABLE_NAME}${whereClause} ` +
      `AND ${field} IS NOT NULL AND ${field} != '' ` +
      `GROUP BY ${field}`
    ).join(' UNION ALL ');

    // --- Products query: limited ---
    const productsQuery =
      `SELECT ${PRODUCT_COLUMNS}, ` +
      `(SELECT COUNT(*) FROM ${TABLE_NAME}${whereClause}) as total_count ` +
      `FROM ${TABLE_NAME}${whereClause} ` +
      `ORDER BY price DESC, unit_name, height_normal_in, color ` +
      `LIMIT 5`;

    // Duplicate args for each facet subquery + products query
    const facetArgs = [];
    for (let i = 0; i < FACET_FIELDS.length; i++) {
      facetArgs.push(...args);
    }
    const productArgs = [...args];

    return {
      json: {
        ...item.json,
        facetsSql: facetQueries,
        facetsArgs: facetArgs,
        productsSql: productsQuery,
        productsArgs: [...args, ...args],
      },
    };
  });

  return out;
